        "id": "ch03-field-roles",
        "role": "interpret",
        "code": "field_roles = {\n    \"identifier_time\": [\"instant\", \"dteday\", \"yr\", \"mnth\", \"hr\", \"weekday\"],\n    \"calendar_category\": [\"season\", \"holiday\", \"workingday\"],\n    \"weather_category\": [\"weathersit\"],\n    \"normalized_continuous\": [\"temp\", \"atemp\", \"hum\", \"windspeed\"],\n    \"count\": [\"casual\", \"registered\", \"cnt\"],\n}\nfield_roles\n"
