        "code": "fig, ax = plt.subplots(figsize=(8, 5))\nsns.scatterplot(\n    data=analysis_rides,\n    x=\"temp\",\n    y=\"cnt\",\n    hue=\"workingday_label\",\n    style=\"workingday_label\",\n    alpha=0.35,\n    ax=ax,\n)\nax.set(\n    title=\"归一化气温与每小时需求\",\n    xlabel=\"归一化气温（摄氏气温 / 41）\",\n    ylabel=\"每小时租车次数\",\n)\nfig.tight_layout()\n"
